  ('aboriginal-0f640084-moex-00021', 'aboriginal-0f640084', 'aboriginal-0f640084-moex-112-6ed013db', 'sub-aboriginal-0f640084-02', NULL, 'single_choice', '根據原住民族工作權保障法，依政府採購法得標之廠商，於國內員工總人數逾100人者，負有應僱用一定 比例原住民之要求。下列有關此規定之敘述，何者錯誤？', '["其僱用之人數不得低於總人數百分之一", "若僱用之人數未達標準，則須繳納代金", "應於履約期間符合僱用一定比例之義務", "於投標時即須符合僱用一定比例之義務"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:08+00:00", "source_pdf_sha1": "384194208de1", "answer_pdf_sha1": "a334f7cbe936", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "516", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "電力工程"}'::jsonb, NULL),
